async (params, browser) => {
  // Open question page
  await browser.open(`${params.question_url}`)

  // Wait for answers to load
  await browser.waitForSelector('#answers, .answer, [data-answerid]', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load answers
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Scroll even further
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(1500)

  // Extract answers
  const answers_data = await browser.evaluate(`const titleEl = document.querySelector('#question-header h1 a, h1'); const answers = []; const answerEls = document.querySelectorAll('.answer, [data-answerid]'); for (let i = 0; i < Math.min(answerEls.length, 15); i++) { const el = answerEls[i]; const bodyEl = el.querySelector('.s-prose, .post-text, .js-post-body'); const votesEl = el.querySelector('.js-vote-count'); const authorEl = el.querySelector('.user-details a, .post-signature:last-child .user-details a'); const dateEl = el.querySelector('.relativetime, time'); const isAccepted = el.classList.contains('accepted-answer') || !!el.querySelector('.js-accepted-answer-indicator:not(.d-none)'); const commentEls = el.querySelectorAll('.comment-body, .comment-text'); const comments = []; commentEls.forEach(function(c, idx) { if (idx < 3) { const userEl = c.querySelector('.comment-user, a'); comments.push({ author: userEl ? userEl.textContent.trim() : '', text: c.textContent.trim().substring(0, 200) }); } }); answers.push({ answer_id: el.getAttribute('data-answerid') || '', is_accepted: isAccepted, votes: votesEl ? votesEl.textContent.trim() : '0', body: bodyEl ? bodyEl.textContent.trim().substring(0, 1500) : '', author: authorEl ? authorEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', comment_count: commentEls.length, comments: comments }); } return { question_title: titleEl ? titleEl.textContent.trim() : '', answer_count: answers.length, answers: answers, url: window.location.href }`)

  return answers_data
}
